// Load dependency watch list
const dependencies = [
  { name: 'stripe', current_version: '12.3.0', package_registry: 'npm', api_endpoint_to_probe: 'https://api.stripe.com/v1', expected_header: 'stripe-version', notes: 'Stripe deprecated API version 2022-08-01 on Jan 1 2026' },
  { name: 'openai', current_version: '4.11.0', package_registry: 'npm', api_endpoint_to_probe: null, expected_header: null, notes: 'Pinned to gpt-4o-mini. Check for model deprecation.' },
  { name: 'express', current_version: '4.18.2', package_registry: 'npm', api_endpoint_to_probe: null, expected_header: null, notes: 'Express 5 is stable — v4 still active but planning migration needed' },
  { name: 'react', current_version: '18.2.0', package_registry: 'npm', api_endpoint_to_probe: null, expected_header: null, notes: 'React 19 released — check breaking changes for upgrade path' }
];
const api_contracts = [
  { name: 'Stripe API', endpoint: 'https://api.stripe.com/v1', method: 'GET', check_sunset_header: true },
  { name: 'PostHog API', endpoint: 'https://app.posthog.com/api/projects', method: 'GET', check_sunset_header: true }
];
return [{ json: { dependencies, api_contracts, checked_at: new Date().toISOString() } }];

// Simulate npm registry version check (real implementation: GET https://registry.npmjs.org/{package}/latest)
const { dependencies, api_contracts, checked_at } = $input.first().json;
const latestVersions = { stripe: '14.21.0', openai: '4.52.0', express: '5.0.0', react: '19.0.0' };
const versionWarnings = dependencies.map(dep => {
  const latest = latestVersions[dep.name] || dep.current_version;
  const currentMajor = parseInt(dep.current_version.split('.')[0]);
  const latestMajor = parseInt(latest.split('.')[0]);
  const majorsBehind = latestMajor - currentMajor;
  const status = majorsBehind >= 2 ? 'critical' : majorsBehind === 1 ? 'warning' : 'ok';
  return {
    name: dep.name,
    current_version: dep.current_version,
    latest_version: latest,
    majors_behind: majorsBehind,
    status,
    notes: dep.notes
  };
});
const warnings = versionWarnings.filter(w => w.status !== 'ok');
return [{ json: { version_warnings: versionWarnings, actionable_warnings: warnings, api_contracts, checked_at, meta: { total: dependencies.length, critical: warnings.filter(w=>w.status==='critical').length, warning: warnings.filter(w=>w.status==='warning').length } } }];

const { actionable_warnings: w, meta: m, checked_at } = $input.first().json;
const critical = w.filter(x=>x.status==='critical');
const warning = w.filter(x=>x.status==='warning');
const fmt = arr => arr.map(d => `  [${d.status.toUpperCase()}] ${d.name}: ${d.current_version} → ${d.latest_version} (${d.majors_behind} major${d.majors_behind>1?'s':''} behind)\n  Note: ${d.notes}`).join('\n');
const report = [
  `DEPENDENCY & API DEPRECATION REPORT`,
  `Checked: ${checked_at} | Total: ${m.total} | Critical: ${m.critical} | Warning: ${m.warning}`,
  ``,
  critical.length > 0 ? `CRITICAL (immediate action required):\n${fmt(critical)}` : '',
  warning.length > 0 ? `\nWARNING (plan upgrade):\n${fmt(warning)}` : '',
  ``,
  `RECOMMENDED ACTIONS:`,
  ...critical.map(d=>`  • Upgrade ${d.name} this sprint — ${d.majors_behind} major versions behind`),
  ...warning.map(d=>`  • Plan ${d.name} migration — ${d.majors_behind} major version behind. Review breaking changes.`),
].filter(Boolean).join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
